const body = $input.first().json.body || $input.first().json;

const user_id = body.user_id || null;
const email = body.email || null;
const plan_tier = (body.plan_tier || 'free').toLowerCase().trim();
const current_balance = parseInt(body.current_balance ?? 0, 10);

if (!user_id) throw new Error('Missing required field: user_id');
if (!email) throw new Error('Missing required field: email');

const validTiers = ['free', 'starter', 'pro', 'scale'];
const resolvedTier = validTiers.includes(plan_tier) ? plan_tier : 'free';

// Upgrade path map
const upgradeMap = {
  free:    { next_tier: 'starter', next_credits: 100,  stripe_link: process.env.STRIPE_LINK_STARTER || 'https://nova-ops.space/upgrade/starter' },
  starter: { next_tier: 'pro',     next_credits: 500,  stripe_link: process.env.STRIPE_LINK_PRO     || 'https://nova-ops.space/upgrade/pro' },
  pro:     { next_tier: 'scale',   next_credits: 9999, stripe_link: process.env.STRIPE_LINK_SCALE   || 'https://nova-ops.space/upgrade/scale' },
  scale:   { next_tier: null,      next_credits: null, stripe_link: null }
};

const upgrade = upgradeMap[resolvedTier];
const is_scale = resolvedTier === 'scale';

const planLabels = {
  free: 'Free',
  starter: 'Starter ($49/mo)',
  pro: 'Pro ($149/mo)',
  scale: 'Scale ($299/mo)'
};

return [{
  json: {
    user_id,
    email,
    plan_tier: resolvedTier,
    plan_label: planLabels[resolvedTier],
    current_balance,
    is_scale,
    next_tier: upgrade.next_tier,
    next_credits: upgrade.next_credits,
    stripe_link: upgrade.stripe_link,
    now: new Date().toISOString()
  }
}];

// Scale users should never hit zero — log anomaly and exit
const origin = $('Parse & Validate').first().json;
console.warn(`ANOMALY: Scale user ${origin.user_id} triggered credit exhaustion gate. Balance: ${origin.current_balance}`);
return [{
  json: {
    ...origin,
    anomaly: true,
    message: 'Scale tier user hit credit exhaustion — investigate billing or credit deduction logic'
  }
}];

