// Build the upsell email body for non-scale users
const origin = $('Parse & Validate').first().json;

const nextTierLabels = {
  starter: 'Starter — $49/mo',
  pro:     'Pro — $149/mo',
  scale:   'Scale — $299/mo'
};

const currentCredits = {
  free:    10,
  starter: 100,
  pro:     500
};

const emailHtml = `
<div style="font-family: sans-serif; max-width: 560px; margin: 0 auto; color: #1a1a1a;">
  <h2 style="color: #0f172a;">You've run out of Nova OPS credits</h2>
  <p>Hey there,</p>
  <p>Your <strong>${origin.plan_label}</strong> plan includes <strong>${currentCredits[origin.plan_tier] || 0} credits/month</strong> — and you've used them all.</p>
  <p>Your tools are paused until you upgrade or your credits renew next cycle.</p>
  <hr style="border: none; border-top: 1px solid #e2e8f0; margin: 24px 0;" />
  <h3 style="margin-bottom: 4px;">Upgrade to ${nextTierLabels[origin.next_tier]}</h3>
  <p style="margin-top: 4px;">Get <strong>${origin.next_credits === 9999 ? 'unlimited' : origin.next_credits} credits</strong> per month — plus all the features of the next tier unlocked immediately.</p>
  <a href="${origin.stripe_link}" style="display: inline-block; margin-top: 16px; padding: 12px 28px; background: #6366f1; color: white; border-radius: 8px; text-decoration: none; font-weight: 600;">Upgrade Now →</a>
  <hr style="border: none; border-top: 1px solid #e2e8f0; margin: 32px 0;" />
  <p style="font-size: 13px; color: #64748b;">Questions? Reply to this email or reach us at support@nova-ops.space</p>
  <p style="font-size: 12px; color: #94a3b8;">Nova OPS · Tampa, FL · <a href="https://nova-ops.space" style="color: #94a3b8;">nova-ops.space</a></p>
</div>
`.trim();

const emailText = `You've used all your Nova OPS credits on your ${origin.plan_label} plan (${currentCredits[origin.plan_tier] || 0} credits/month).\n\nUpgrade to ${nextTierLabels[origin.next_tier]} for ${origin.next_credits === 9999 ? 'unlimited' : origin.next_credits} credits per month.\n\nUpgrade here: ${origin.stripe_link}\n\nQuestions? support@nova-ops.space`;

return [{
  json: {
    ...origin,
    email_subject: "You've used all your Nova OPS credits — upgrade for more",
    email_html: emailHtml,
    email_text: emailText
  }
}];

// Confirm email was accepted — Resend returns { id: 'email_xxx' } on success
const sendResult = $input.first().json;
const origin = $('Build Upsell Email').first().json;

const email_id = sendResult?.id || null;
const email_sent = !!email_id;

if (!email_sent) {
  console.warn(`Upsell email may have failed for user ${origin.user_id}. Resend response:`, JSON.stringify(sendResult));
}

return [{
  json: {
    user_id: origin.user_id,
    email: origin.email,
    plan_tier: origin.plan_tier,
    next_tier: origin.next_tier,
    current_balance: origin.current_balance,
    email_sent,
    email_id,
    now: origin.now
  }
}];
